* @Descripttion: 页面模板
-->
<template>
  <LTPages
      :title="'页面模板'"
      isNormal
  >
    <template v-slot:content>
      <div class="Docs-Body">
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">适应 视频监控平台的 页面模板。</div>
        </div>
        <!--1、基本用法-->
        <div class="zhb-title">基本用法</div>
        <div style="margin-bottom:15px;width: 300px;">
          <el-button @click="isLookPic = true">示例1</el-button>
          <LTLookPic v-if="isLookPic" :url="require('./img/template.png')" @picClose="isLookPic = false"></LTLookPic>
          <el-button @click="isLookPic2 = true">示例2</el-button>
          <LTLookPic v-if="isLookPic2" :url="require('./img/user2.png')" @picClose="isLookPic2 = false"></LTLookPic>

        </div>
        <!--2、代码示例2-->
        <div class="zhb-title">代码示例1</div>
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">代码示例1:是视频平台中 常规的增删改查页面，适用于 添加、修改、删除、查询、分页。
          通过使用组件【LTPages】，配置相关参数，即可实现页面的展示。</div>
        </div>
        <!--template-->
        <codeCopy :code="mainCode" id="LTTooltip1" title="template"></codeCopy>
        <!--javaScript-->
        <codeCopy :code="jsCode" id="LTActionsForm2" title="javaScript"></codeCopy>
        <h1></h1>
        <div class="zhb-title">代码示例2</div>
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">代码示例1:是视频平台中 常规页面，只配置了标题，内容区域自定义。</div>
        </div>
        <!--template-->
        <codeCopy :code="mainCode1" id="LTTooltip1" title="template"></codeCopy>
        <!--3、配置参数-->
        <div class="zhb-title">配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>




      </div>
    </template>
  </LTPages>
</template>

<script>
export default {
  data() {
    return {
      isLookPic: false,
      isLookPic2: false,
      mainCode: `<template>
  <div class="Role-body">
    <LTPages
        :title="'角色管理'"
        :isNormal="false"
        :formConfig="formConfig"
        :buttonConfig="buttonConfig"
        :tableConfig="tableConfig"
        @setSearchFields="getSearchFields"
        @tablePageForm="getTableForm"
        @setSelectionTable="getSelectionTable"
    ></LTPages>
    <!--新增角色===============-->
    <LTDialog
        v-if="RoleMsg.isShow"
        :DialogLTMsg="RoleMsg"
        @close="RoleMsg.isShow = false">
      <addRole :role-msg="RoleMsg" @CloseDialog="CloseDialog"></addRole>
    </LTDialog>
    <!--到底啦！===============-->
  </div>
</template>`,
      jsCode: `export default {
  name: "Role",
  components: {
    addRole
  },
  data() {
    return {
      //搜索配置
      formConfig: {
        itemNum: 5,
        labelWidth: '80px',
        formItemList: [
          {
            id: 1,
            type: 'text',
            prop: 'roleName',
            label: '角色名称',
            value: ''
          }
        ]
      },
      // 按钮
      buttonConfig: [
        {
          label: '添加',
          icon: "icon zhb-iconfont zhb-iconzengjia",
          click: () => {
            this.RoleMsg.type = 'add'
            this.RoleMsg.title = '新增角色'
            this.RoleMsg.isShow = true;
          }
        },
        {
          label: '删除',
          icon: "icon zhb-iconfont zhb-iconshanchu2",
          click: () => {
            if (this.checkTabelData.length == 0) return this.$message.warning({
              message: "请至少选择一条表格数据！",
              showClose: true,
              duration: 1000
            });
            if (this.checkTabelData[0].isPreset == 1) return this.$message.warning({
              message: "系统预制角色不可删除！",
              showClose: true,
              duration: 1000
            });
            this.$confirm('此操作将永久删除该角色, 是否继续?', '提示', {
              confirmButtonText: '确定',
              cancelButtonText: '取消',
              type: 'warning'
            }).then(() => {

              var ids = []
              this.checkTabelData.forEach(item => {
                ids.push(item.id)
              })
              RoleApi.deleteRoleApi({ids: ids}).then(res => {
                if (res.data.code != '2000') return this.$message.error({
                  message: res.data.message,
                  showClose: true,
                  duration: 1000
                });
                this.queryRole()
                this.$message({
                  type: 'success',
                  message: '删除成功！'
                });
              })
            }).catch(() => {
              this.$message({
                type: 'info',
                message: '已取消删除'
              });
            });
          }
        }
      ],
      //表格配置
      tableConfig: {
        tableRefresh: true,
        tableHead: [
          {
            label: '角色名称',
            prop: 'roleName',
          },
          {
            label: '角色描述',
            prop: 'remarks',
          },
          {
            label: '创建时间',
            prop: 'createTime',
          },
        ],
        tableData: [],
        columnButton: [],
        columnWidth: '130',
        // tableColWidth:'155',
        total: 0,
        pageSize: 20,
        currentPage: 1,
      },
      //表格勾选
      checkTabelData: [],
      //查询参数
      params: {
        pageSize: 20,
        currentPage: 1,
      },
      RoleMsg: {
        isShow: false,
        title: '添加角色',
        showCloseBtn: true,
        styles: {
          width: '50%',
          height: '80%'
        }
      }
    };
  },
  created() {
    this.queryRole();
  },
  methods: {
    getSearchFields(data) {
      console.log(data);
      if (data.type != 'reset') {
        this.params.roleName = data.roleName
        this.params.currentPage = 1;
        this.tableConfig.currentPage = 1;
      } else { //重置
        this.params = {
          pageSize: 20,
          currentPage: 1
        }
      }
      this.queryRole();
    },
    //表格分页变化回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.params.pageSize = page.pageSize;
      this.params.currentPage = page.pageNum;
      this.queryRole();
    },
    // 勾选
    getSelectionTable(val) {
      this.checkTabelData = val;
    },
    // 查询
    queryRole() {
      RoleApi.queryRoleApi(this.params).then(res => {

        if (res.data.code != '2000') return this.$message.error({
          message: res.data.message,
          showClose: true,
          duration: 1000
        });
        this.tableConfig.tableData = res.data.result.records
        this.tableConfig.total = res.data.result.total
      })
    },
    // 关闭弹窗
    CloseDialog(val) {
      if (val == 0) {
        this.RoleMsg.isShow = false;
        this.queryRole()
      } else {
        this.RoleMsg.isShow = false;
      }
    }


  }
}`,
      mainCode1: `<template>
  <LTPages
      is-normal
      :title="'用户管理'"
  >
    <template v-slot:content>
    【自定义页面内容】
    </template>
  </LTPages>
</template>`,
      tableData:[
        {
          text1:'is-normal',
          text2:'是否基础模板',
          text3:'Boolean',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'title',
          text2:'模板标题',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'formConfig',
          text2:'查询条件配置',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'buttonConfig',
          text2:'按钮配置',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'tableConfig',
          text2:'表格配置',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'@setSearchFields',
          text2:'查询条件事件回调',
          text3:'Function',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'@tablePageForm',
          text2:'表格分页事件回调',
          text3:'Function',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'@setSelectionTable',
          text2:'表格勾选事件回调',
          text3:'Function',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'@setTableCol',
          text2:'表格列点击事件回调',
          text3:'Function',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'@setDblClick',
          text2:'表格双击事件回调',
          text3:'Function',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'defaultSelection',
          text2:'组件内方法',
          text3:'Function',
          text4:'---',
          text5:'---',
          text6:'设置表格默认勾选',
        },
      ]
    }
  }
}
</script>

